import { type FormEvent, useState } from 'react';

interface FormState {
  name: string;
  email: string;
  password: string;
}

interface FormErrors {
  name?: string;
  email?: string;
  password?: string;
}

function validate(values: FormState): FormErrors {
  const errors: FormErrors = {};
  if (!values.name || values.name.trim().length < 2) errors.name = 'Name must be at least 2 characters.';
  if (!values.email || !/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(values.email)) errors.email = 'Enter a valid email address.';
  if (!values.password || values.password.length < 8) errors.password = 'Password must be at least 8 characters.';
  return errors;
}

export function SignupForm() {
  const [values, setValues] = useState<FormState>({ name: '', email: '', password: '' });
  const [errors, setErrors] = useState<FormErrors>({});
  const [touched, setTouched] = useState<Partial<Record<keyof FormState, boolean>>>({});
  const [submitted, setSubmitted] = useState(false);

  function handleBlur(field: keyof FormState) {
    setTouched(prev => ({ ...prev, [field]: true }));
    setErrors(validate(values));
  }

  function handleChange(field: keyof FormState, value: string) {
    const next = { ...values, [field]: value };
    setValues(next);
    if (touched[field]) setErrors(validate(next));
  }

  function handleSubmit(e: FormEvent) {
    e.preventDefault();
    const allTouched = { name: true, email: true, password: true };
    setTouched(allTouched);
    const errs = validate(values);
    setErrors(errs);
    if (Object.keys(errs).length === 0) setSubmitted(true);
  }

  const hasErrors = Object.keys(errors).length > 0;
  const isEmpty = !values.name || !values.email || !values.password;

  if (submitted) {
    return <p style={{ color: '#16a34a', fontWeight: 600 }}>Account created successfully!</p>;
  }

  return (
    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1rem', minWidth: '20rem' }}>
      <h2 style={{ fontWeight: 700, fontSize: '1.5rem' }}>Sign Up</h2>

      {(['name', 'email', 'password'] as const).map((field) => (
        <div key={field} style={{ display: 'flex', flexDirection: 'column', gap: '0.25rem' }}>
          <label style={{ fontSize: '0.875rem', fontWeight: 500, textTransform: 'capitalize' }}>{field}</label>
          <input
            type={field === 'password' ? 'password' : field === 'email' ? 'email' : 'text'}
            value={values[field]}
            onChange={e => handleChange(field, e.target.value)}
            onBlur={() => handleBlur(field)}
            style={{
              padding: '0.5rem 0.75rem',
              border: `1px solid ${touched[field] && errors[field] ? '#ef4444' : '#d1d5db'}`,
              borderRadius: '0.375rem',
              fontSize: '0.875rem',
            }}
          />
          {touched[field] && errors[field] && (
            <p style={{ color: '#ef4444', fontSize: '0.75rem', margin: 0 }}>{errors[field]}</p>
          )}
        </div>
      ))}

      <button
        type="submit"
        disabled={hasErrors || isEmpty}
        style={{
          padding: '0.5rem 1rem',
          background: hasErrors || isEmpty ? '#d1d5db' : '#f59e0b',
          color: hasErrors || isEmpty ? '#6b7280' : '#000',
          fontWeight: 600,
          borderRadius: '0.375rem',
          border: 'none',
          cursor: hasErrors || isEmpty ? 'not-allowed' : 'pointer',
        }}
      >
        Create Account
      </button>
    </form>
  );
}
